1	package claudecode
2	
3	import (
4		"encoding/json"
5		"os"
6		"path/filepath"
7		"strings"
8		"syscall"
9	
10		"irrlicht/core/adapters/inbound/agents/processlifecycle"
11	)
12	
13	// sessionsDir is the directory Claude Code writes per-process metadata files to.
14	// Each live Claude process owns ~/.claude/sessions/<pid>.json containing
15	// {"pid":N,"sessionId":"<uuid>","cwd":"...","startedAt":...}.
16	// Overridable in tests via the test helper in pid_test.go.
17	var sessionsDir = defaultSessionsDir()
18	
19	func defaultSessionsDir() string {
20		home, err := os.UserHomeDir()
21		if err != nil {
22			return ""
23		}
24		return filepath.Join(home, ".claude", "sessions")
25	}
26	
27	// claudeSessionMeta mirrors the on-disk schema of ~/.claude/sessions/<pid>.json.
28	// Only the fields we need are declared.
29	type claudeSessionMeta struct {
30		PID       int    `json:"pid"`
31		SessionID string `json:"sessionId"`
32		CWD       string `json:"cwd"`
33	}
34	
35	// DiscoverPID finds the Claude Code process owning a session. It prefers an
36	// authoritative lookup in ~/.claude/sessions/<pid>.json (where Claude writes a
37	// direct PID↔sessionId mapping for every live process) and falls back to
38	// CWD-based matching only when that metadata is missing.
39	//
40	// The CWD fallback is restricted: if more than one live Claude process matches
41	// the CWD after excluding PIDs that belong to other sessions (per metadata),
42	// DiscoverPID returns 0 (unknown — retry later) rather than guessing. This
43	// prevents the flap loop in issue #109 where cwd-only matching would bind a
44	// new transcript to a PID already legitimately owned by another session,
45	// triggering destructive duplicate-PID cleanup.
46	func DiscoverPID(cwd, transcriptPath string, disambiguate func([]int) int) (int, error) {
47		wantSessionID := sessionIDFromTranscript(transcriptPath)
48	
49		// Layer 1: authoritative metadata lookup.
50		// Scan ~/.claude/sessions/*.json once, collecting PIDs that some metadata
51		// file owns (for negative-filtering the fallback) and looking for an
52		// exact sessionId match.
53		claimedByOthers := make(map[int]bool)
54		if wantSessionID != "" && sessionsDir != "" {
55			entries, err := os.ReadDir(sessionsDir)
56			if err == nil {
57				for _, e := range entries {
58					if e.IsDir() || !strings.HasSuffix(e.Name(), ".json") {
59						continue
60					}
61					meta, ok := readSessionMeta(filepath.Join(sessionsDir, e.Name()))
62					if !ok {
63						continue
64					}
65					if !pidAlive(meta.PID) {
66						continue
67					}
68					if meta.SessionID == wantSessionID {
69						return meta.PID, nil
70					}
71					// A live Claude process owns this PID for a different sessionId;
72					// exclude it from the cwd fallback below.
73					claimedByOthers[meta.PID] = true
74				}
75			}
76		}
77	
78		// Layer 2: restricted CWD fallback.
79		// Used when the metadata file for this session hasn't appeared yet (brief
80		// startup window) or when transcriptPath is empty. Never guesses between
81		// competing candidates — DiscoverPIDWithRetry will retry shortly.
82		wrapped := func(pids []int) int {
83			filtered := pids[:0:0]
84			for _, p := range pids {
85				if claimedByOthers[p] {
86					continue
87				}
88				filtered = append(filtered, p)
89			}
90			switch len(filtered) {
91			case 0:
92				return 0
93			case 1:
94				return filtered[0]
95			default:
96				// Ambiguous: multiple live claude processes share this cwd and
97				// none are disambiguated by metadata. Returning 0 causes the
98				// caller to retry, giving Claude time to write its metadata file.
99				return 0
100			}
101		}
102		// The disambiguate arg from the caller (PIDManager.TryDiscoverPID) is
103		// deliberately ignored: its "prefer unclaimed, else highest PID" strategy
104		// is the exact behavior that lets a new session steal a rival's PID.
105		// The wrapped callback above enforces the stricter unambiguous rule.
106		_ = disambiguate
107		return discoverByCWD("claude", cwd, wrapped)
